import xml.etree.ElementTree as ET

def validate_xml(file):
    try:
        tree = ET.parse(file)
        root = tree.getroot()
        return True, "XML is valid."
    except ET.ParseError as e:
        return False, f"XML validation failed: {str(e)}"

# Example usage
